// Twisted hex vase — spiraling hex facets with a graceful flowing silhouette:
// flared foot, a pinched ankle, a full belly bulge, a tapered shoulder, a
// neck pinch, and a flared rim. Built from stacked, tapered hex rings that
// overlap in Z so the whole piece fuses into one watertight solid.
const { Manifold, label } = api;

const height = 30; // overall height (Z-up)
const slices = 72; // rings — smooth silhouette, still low tri-count
const sides = 6; // hex cross-section (the faceted identity)
const totalTwist = 150; // degrees of spiral over the full height

// Radius profile control points [t (0..1), radius], Catmull-Rom interpolated
// for a flowing vase silhouette (no hard kinks).
const ctrl = [
  [0.00, 3.6], // flared foot base
  [0.06, 4.2], // foot lip — widest point of the foot
  [0.12, 3.0], // ankle pinch above the foot
  [0.45, 7.2], // belly bulge (sits just below mid-height)
  [0.70, 5.0], // shoulder
  [0.85, 3.3], // neck pinch
  [1.00, 4.4], // flared rim lip
];

function catmull(p0, p1, p2, p3, t) {
  const t2 = t * t,
    t3 = t2 * t;
  return 0.5 * ((2 * p1) + (-p0 + p2) * t +
    (2 * p0 - 5 * p1 + 4 * p2 - p3) * t2 +
    (-p0 + 3 * p1 - 3 * p2 + p3) * t3);
}

function radiusAt(tt) {
  const n = ctrl.length;
  if (tt <= ctrl[0][0]) return ctrl[0][1];
  if (tt >= ctrl[n - 1][0]) return ctrl[n - 1][1];
  for (let i = 0; i < n - 1; i++) {
    if (tt >= ctrl[i][0] && tt <= ctrl[i + 1][0]) {
      const t0 = ctrl[i][0],
        r0 = ctrl[i][1];
      const t1 = ctrl[i + 1][0],
        r1 = ctrl[i + 1][1];
      const local = (tt - t0) / (t1 - t0);
      const rp0 = i - 1 >= 0 ? ctrl[i - 1][1] : r0;
      const rp3 = i + 2 < n ? ctrl[i + 2][1] : r1;
      return catmull(rp0, r0, r1, rp3, local);
    }
  }
  return ctrl[n - 1][1];
}

const sliceH = height / slices;
const overlap = 0.6; // each ring overlaps its neighbor in Z (> 0.5 -> one solid)

// Group rings into foot / body / rim bands so each can be colored with a
// COMPACT byLabel descriptor (no baked triangle-id lists) — keeps the catalog
// file small and the two-tone glaze reconstructs deterministically.
const footRings = [],
  bodyRings = [],
  rimRings = [];
for (let i = 0; i < slices; i++) {
  const t = i / (slices - 1);
  const tNext = (i + 1) / (slices - 1);
  const z = t * (height - sliceH);
  const twist = t * totalTwist;
  // Tapered hex ring: bottom radius = profile(t), top radius = profile(t+1),
  // so adjacent rings meet at matching radii for a continuous faceted surface.
  const ring = Manifold
    .cylinder(sliceH + overlap, radiusAt(t), radiusAt(tNext), sides)
    .rotate([0, 0, twist])
    .translate([0, 0, z]);
  if (z < 2.7) footRings.push(ring);
  else if (z > 25.0) rimRings.push(ring);
  else bodyRings.push(ring);
}

const parts = [label(Manifold.union(bodyRings), 'body')];
if (footRings.length) parts.push(label(Manifold.union(footRings), 'foot'));
if (rimRings.length) parts.push(label(Manifold.union(rimRings), 'rim'));
return Manifold.union(parts);
